mapper.select:
		 SELECT * FROM (
        SELECT ROWNUM AS RN, A.* FROM (
            SELECT P.*, NVL(L.LIKE_COUNT, 0) AS LIKE_COUNT
            FROM POST P
            LEFT JOIN (
                SELECT P_NUMBER, COUNT(*) AS LIKE_COUNT
                FROM P_LIKE
                GROUP BY P_NUMBER
            ) L ON P.P_NUMBER = L.P_NUMBER
            ORDER BY P.P_NUMBER DESC
        ) A
        WHERE ROWNUM <= #{endRow}
    )
    WHERE RN >= #{startRow}

